import { filesOfProject } from "ts-arch";

it("domain 层不应依赖 ui 层", async () => {
  const rule = filesOfProject()
    .inFolder("src/domain")
    .shouldNot()
    .dependOnFiles()
    .inFolder("src/ui");

  await expect(rule).toPass();
});
```

收益：

